def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0
        for j in range(1, 21):
            base = ((-1)**(j+1)) * np.sin(ratio * j * np.pi/4) / (j + 0.5)
            if j % 4 == 0:
                base *= (1 + 0.05 * j)
            elif j % 3 == 0:
                base *= 0.9
            else:
                base *= 1.1
            score += base
        remainder = capacity - item
        if remainder < 0.05 * capacity:
            score *= 2.2
        elif remainder < 0.15 * capacity:
            score *= 1.6
        elif remainder < 0.4 * capacity:
            score *= 1.1
        else:
            score *= 0.7
        if int(capacity) % 4 == 0 and int(capacity) % 6 == 0:
            score -= 0.2 * (capacity / 12)
        elif int(capacity) % 4 == 0:
            score -= 0.1 * (capacity / 15)
        elif int(capacity) % 6 == 0:
            score -= 0.15 * (capacity / 20)
        else:
            score -= 0.05 * (capacity / 25)
        temp_penalty = 0
        for multiple in range(1, 8):
            val = multiple * item
            diff = abs(capacity - val)
            threshold = 0.02 * capacity * multiple
            if diff < threshold:
                temp_penalty += (0.3 / multiple) * np.log1p(capacity)
            else:
                temp_penalty -= 0.02 * multiple
        score += temp_penalty * 0.8
        complex_adjust = 0
        for a in range(1, 4):
            for b in range(1, 5):
                if abs(((capacity/(a+b)) - item)) < 0.015 * capacity:
                    complex_adjust += 0.01 * a * b * np.exp(-ratio * (a+b))
        score += complex_adjust
        if score < 0:
            score = 0
        if score > 2:
            for n in range(1, 5):
                if abs((capacity / (n + 0.5)) - item) < 0.03 * capacity:
                    score *= 1 + 0.04 * n
        priorities[i] = score
    return priorities
